create table dirkspzm32.s_mfr_send_offline (
    firma_nr   number(2, 0) not null enable,
    offline_id number(*, 0) not null enable,
    auf_id     number(*, 0),
    satzart    varchar2(2 char),
    funktion   number(4, 0),
    auftrag    number(10, 0),
    lte_id     varchar2(20 char),
    gen_datum  date,
    quelle     varchar2(20 char),
    ziel       varchar2(20 char),
    telegramm  varchar2(512 char) not null enable,
    gruppe     varchar2(20 char)
);

alter table dirkspzm32.s_mfr_send_offline
    add constraint pk_s_mfr_send_offline primary key ( offline_id )
        using index enable;


